CREATE TABLE IF NOT EXISTS risk_vendors(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,name text NOT NULL,owner text NOT NULL,criticality text NOT NULL,status text NOT NULL,services jsonb NOT NULL DEFAULT '[]',data_access jsonb NOT NULL DEFAULT '[]',renewal_at timestamptz,risk_score numeric NOT NULL DEFAULT 0,risk_band text NOT NULL,next_review_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS vendor_questionnaires(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,vendor_id uuid NOT NULL,name text NOT NULL,status text NOT NULL,questions jsonb NOT NULL DEFAULT '[]',answers jsonb NOT NULL DEFAULT '{}',score numeric NOT NULL DEFAULT 0,submitted_at timestamptz,reviewed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS vendor_assurance_documents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,vendor_id uuid NOT NULL,type text NOT NULL,reference text NOT NULL,period_end timestamptz,expires_at timestamptz,status text NOT NULL,exceptions jsonb NOT NULL DEFAULT '[]',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS vendor_risk_reviews(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,vendor_id uuid NOT NULL,reviewer text NOT NULL,score numeric NOT NULL,risk_band text NOT NULL,findings jsonb NOT NULL DEFAULT '[]',status text NOT NULL,reviewed_at timestamptz NOT NULL,next_review_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());CREATE INDEX IF NOT EXISTS idx_risk_vendor_review ON risk_vendors(tenant_id,criticality,next_review_at);
